import numpy as np from typing import List, Tuple
def cosine_similarity(a: np.ndarray, b: np.ndarray) -> float: return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b)))
def find_most_similar( query_embedding: np.ndarray, document_embeddings: np.ndarray, top_k: int = 5, ) -> List[Tuple[int, float]]: """Vectorised cosine search; assumes document_embeddings is (N, D).""" norms = np.linalg.norm(document_embeddings, axis=1) * np.linalg.norm(query_embedding) similarities = np.dot(document_embeddings, query_embedding) / norms top_indices = np.argsort(similarities)[::-1][:top_k] return [(int(idx), float(similarities[idx])) for idx in top_indices]
